    dish = None
    for m in menu:
        if int(m['dish_id']) == dish_id:
            dish = {
                'dish_id': m['dish_id'],
                'name': m['name'],
                'price': m['price'],
                'description': m['description']
            }
            break

    if dish is None:
        dish = {
            'dish_id': str(dish_id),
            'name': '',
            'price': '',
            'description': ''
        }

    return render_template('dish_detail.html', dish=dish)


@app.route('/make-reservation', methods=['GET', 'POST'])
def make_reservations():
    if request.method == 'GET':
        return render_template('make_reservation.htm', None=None)

    # POST handling
    guestname = request.form.get('guestname')
    party_size = request.form.get('party_size')
    reservation_date = request.form.get('reservation_date')

    # Validate received data
    if not guestname or not party_size or not reservation_date:
        # Missing data - just re-render GET page
        return render_template('make_reservation.htm', None=None)

    # Load existing reservations for id assignment
    reservations = load_reservations()
    # Generate new unique reservation_id as max existing + 1 or '1'
    max_id = 0
    for r in reservations:
        try:
            cur_id = int(r['reservation_id'])
            if cur_id > max_id:
                max_id = cur_id
        except:
            continue
    new_id = str(max_id + 1)

    # Construct new reservation entry
    new_reservation = {
        'reservation_id': new_id,
        'username': guestname, # We use guestname as username placeholder since no auth
        'guest_name': guestname,
        'phone': '',  # not provided
        'email': '',  # not provided
        'party_size': party_size,
        'date': reservation_date,
        'time': '19:00',  # default time
        'special_requests': '',
        'status': 'Upcoming'
    }

    # Save to reservations.txt (append)
    path = os.path.join(DATA_PATH, 'reservations.txt')
    with open(path, 'a') as f:
        line = ','.join([
            new_reservation['reservation_id'],
            new_reservation['username'],
            new_reservation['guest_name'],
            new_reservation['phone'],
            new_reservation['email'],
            new_reservation['party_size'],
            new_reservation['date'],
            new_reservation['time'],
            new_reservation['special_requests'],
            new_reservation['status']
        ]) + '\n'
        f.write(line)

    return redirect(url_for('dashboard'))


@app.route('/my-reservations', methods=['POST'])
def my_reservations():
    username = request.form.get('username')
    if not username:
        # fallback first user
        users = load_users()
        username = next(iter(users), None)

    reservations = load_reservations()
    user_reservations = []
    for r in reservations:
        if r['username'] == username:
            try:
                dt = datetime.datetime.strptime(r['date'], '%Y-%m-%d')
                date_int = int(dt.strftime('%Y%m%d'))
            except Exception:
                date_int = 0
            try:
                time_int = int(r['time'].replace(':', ''))
            except Exception:
                time_int = 0
            user_reservations.append({
                'reservation_id': r['reservation_id'],
                'date': date_int,
                'time': time_int,
                'party_size': r['party_size'],
                'status': 0 if r['status'].lower() == 'upcoming' else 1
            })

    return render_template('my_reservations.htm', reservations=user_reservations)


@app.route('/cancel-reservation/<int:reservation_id>', methods=['GET'])
def cancel_reservation(reservation_id):
    reservations = load_reservations()
    # Update the reservation with matching id, set status to Canceled
    updated = False
    for r in reservations:
        try:
            if int(r['reservation_id']) == reservation_id:
                r['status'] = 'Canceled'
                updated = True
                break
        except:
            continue

    if updated:
        # Write back all reservations
        path = os.path.join(DATA_PATH, 'reservations.txt')
        with open(path, 'w') as f:
            for r in reservations:
                line = ','.join([
                    r['reservation_id'],
                    r['username'],
                    r['guest_name'],
                    r['phone'],
                    r['email'],
                    r['party_size'],
                    r['date'],
                    r['time'],
                    r['special_requests'],
                    r['status']
                ]) + '\n'
                f.write(line)

    return redirect(url_for('dashboard'))


@app.route('/waitlist', methods=['GET', 'POST'])
def waitlist_page():
    users = load_users()
    # For demo assume username from POST or fallback first
    username = None
    if request.method == 'POST':
        username = request.form.get('username')
    if not username or username not in users:
        username = next(iter(users), None)

    waitlist = load_waitlist()

    # Check if user already in the waitlist with status Active
    user_waitlist_entry = None
    position = None
    active_waitlist = [w for w in waitlist if w['status'].lower() == 'active']

    # Sort waitlist ascending by join_time
    def join_time_key(w):
        try:
            return datetime.datetime.strptime(w['join_time'], '%Y-%m-%d %H:%M:%S')
        except Exception:
            return datetime.datetime.min

    active_waitlist.sort(key=join_time_key)

    for idx, w in enumerate(active_waitlist):
        if w['username'] == username:
            user_waitlist_entry = w
            position = str(idx + 1)
            break

    if request.method == 'POST':
        party_size = request.form.get('party_size')
        if party_size and user_waitlist_entry is None:
            # Add user to waitlist
            max_id = 0
            for w in waitlist:
                try:
                    cur_id = int(w['waitlist_id'])
                    if cur_id > max_id:
                        max_id = cur_id
                except:
                    continue
            new_id = str(max_id + 1)
            now_str = datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            new_entry = {
                'waitlist_id': new_id,
                'username': username,
                'party_size': party_size,
                'join_time': now_str,
                'status': 'Active'
            }
            waitlist.append(new_entry)
            # Save new waitlist to file
            path = os.path.join(DATA_PATH, 'waitlist.txt')
            with open(path, 'w') as f:
                for w in waitlist:
                    line = '|'.join([
                        w['waitlist_id'],
                        w['username'],
                        w['party_size'],
                        w['join_time'],
                        w['status']
                    ]) + '\n'
                    f.write(line)

            # Refresh user_waitlist_entry and position
            user_waitlist_entry = new_entry
            active_waitlist.append(new_entry)
            active_waitlist.sort(key=join_time_key)
            for idx, w in enumerate(active_waitlist):
                if w['username'] == username:
                    position = str(idx + 1)
                    break

    return render_template('waitlist.htm', position=position, user_waitlist_entry=user_waitlist_entry)


@app.route('/my-reviews', methods=['GET'])
def my_reviews():
    # No user identification provided, assume first user
    users = load_users()
    username = next(iter(users), None)

    reviews_all = load_reviews()
    menu = load_menu()

    # Gather reviews by user
    reviews = []
    for r in reviews_all:
        if r['username'] == username:
            # Find dish name from menu
            dish_name = ''
            for m in menu:
                if m['dish_id'] == r['dish_id']:
                    dish_name = m['name']
                    break
            try:
                # Convert review_date YYYY-MM-DD to int YYYYMMDD
                dt = datetime.datetime.strptime(r['review_date'], '%Y-%m-%d')
                review_date_int = int(dt.strftime('%Y%m%d'))
            except Exception:
                review_date_int = 0
            reviews.append({
                'review_id': r['review_id'],
                'dish_name': dish_name,
                'rating': r['rating'],
                'review_text': r['review_text'],
                'review_date': review_date_int
            })

    return render_template('my_reviews.htm', reviews=reviews)


@app.route('/write-review', methods=['GET', 'POST'])
def write_reviews():
    menu = load_menu()
    dishes = []
    for m in menu:
        dishes.append({
            'dish_id': m['dish_id'],
            'name': m['name']
        })

    if request.method == 'GET':
        return render_template('write_review.htm', dishes=dishes)

    # POST method
    try:
        dish_id = request.form.get('dish_id')
        rating = request.form.get('rating')
        review_text = request.form.get('review_text')
        if not dish_id or not rating or not review_text:
            return render_template('write_review.htm', dishes=dishes)

        # Load existing reviews to determine new review_id
        reviews = load_reviews()
        max_id = 0
        for r in reviews:
            try:
                cur_id = int(r['review_id'])
                if cur_id > max_id:
                    max_id = cur_id
            except:
                continue
        new_id = str(max_id + 1)

        # For username, use first user (no auth)
        users = load_users()
        username = next(iter(users), None) or 'guest'

        new_review = {
            'review_id': new_id,
            'username': username,
            'dish_id': dish_id,
            'rating': rating,
            'review_text': review_text,
            'review_date': datetime.datetime.now().strftime('%Y-%m-%d')
        }

        path = os.path.join(DATA_PATH, 'reviews.txt')
        with open(path, 'a') as f:
            line = '|'.join([
                new_review['review_id'],
                new_review['username'],
                new_review['dish_id'],
                new_review['rating'],
                new_review['review_text'],
                new_review['review_date']
            ]) + '\n'
            f.write(line)

        return redirect(url_for('my_reviews'))
    except Exception:
        return render_template('write_review.htm', dishes=dishes)


@app.route('/profile', methods=['GET', 'POST'])
def profile():
    users = load_users()
    username = next(iter(users), None)
    if request.method == 'POST':
        email = request.form.get('email')
        if username and email:
            # Update user email and save back to users.txt
            updated = False
            all_users = []
            path = os.path.join(DATA_PATH, 'users.txt')
            # read all users first
            if os.path.exists(path):
                with open(path, 'r') as f:
                    for line in f:
                        parts = line.strip().split(',')
                        if len(parts) >= 4:
                            user_name = parts[0]
                            user_email = parts[1]
                            phone = parts[2]
                            full_name = parts[3]
                            if user_name == username:
                                user_email = email
                                updated = True
                            all_users.append((user_name, user_email, phone, full_name))

            # write back all users
            if updated:
                with open(path, 'w') as f:
                    for u in all_users:
                        line = ','.join(u) + '\n'
                        f.write(line)

            # reload user profile
            users = load_users()

    user_profile = users.get(username, {'username': username, 'email': ''})
    return render_template('profile.htm', user_profile=user_profile)


